const styles = {
  container: {
    fontFamily: "'JetBrains Mono', monospace",
    backgroundColor: "#0B0F14",
    color: "#E5E7DB",
    minHeight: "100vh",
    padding: 20,
    boxSizing: "border-box",
    display: "flex",
    flexDirection: "column",
  },
  header: {
    marginBottom: 12,
    fontSize: 22,
    fontWeight: "bold",
  },
  tabsContainer: {
    display: "flex",
    marginBottom: 12,
    gap: 8,
  },
  tab: (active) => ({
    cursor: "pointer",
    padding: "6px 14px",
    borderRadius: 6,
    backgroundColor: active ? "#22C55E" : "#0F1620",
    color: active ? "#0B0F14" : "#E5E7DB",
    border: `1px solid #1F2A37`,
    userSelect: "none",
    fontWeight: active ? "bold" : "normal",
    transition: "background-color 0.25s, color 0.25s",
  }),
  filtersRow: {
    display: "flex",
    gap: 12,
    marginBottom: 12,
    flexWrap: "wrap",
    alignItems: "center",
  },
  dateInput: {
    backgroundColor: "#0F1620",
    border: "1px solid #1F2A37",
    color: "#E5E7DB",
    padding: "6px 8px",
    borderRadius: 6,
    fontFamily: "'JetBrains Mono', monospace",
    fontSize: 14,
  },
  searchInput: {
    flexGrow: 1,
    minWidth: 180,
    backgroundColor: "#0F1620",
    border: "1px solid #1F2A37",
    color: "#E5E7DB",
    padding: "6px 8px",
    borderRadius: 6,
    fontFamily: "'JetBrains Mono', monospace",
    fontSize: 14,
  },
  tableWrapper: {
    overflowX: "auto",
    border: "1px solid #1F2A37",
    borderRadius: 6,
    marginBottom: 12,
  },
  table: {
    width: "100%",
    borderCollapse: "collapse",
    fontSize: 14,
  },
  th: {
    backgroundColor: "#0F1620",
    borderBottom: "1px solid #1F2A37",
    padding: "10px 12px",
    cursor: "pointer",
    userSelect: "none",
    textAlign: "left",
    whiteSpace: "nowrap",
    position: "relative",
  },
  thSortIndicator: {
    marginLeft: 8,
    fontSize: 13,
    userSelect: "none",
  },
  td: {
    padding: "10px 12px",
    borderBottom: "1px solid #1F2A37",
    whiteSpace: "nowrap",
  },
  greenText: {
    color: "#22C55E",
  },
  redText: {
    color: "#EF4444",
  },
  summaryBar: {
    backgroundColor: "#0F1620",
    border: "1px solid #1F2A37",
    borderRadius: 6,
    padding: 12,
    display: "flex",
    justifyContent: "space-around",
    fontWeight: "bold",
    fontSize: 16,
    marginBottom: 12,
  },
  summaryItem: {
    userSelect: "none",
  },
  pagination: {
    display: "flex",
    justifyContent: "center",
    gap: 8,
    marginTop: 8,
    flexWrap: "wrap",
  },
  pageButton: (active) => ({
    cursor: "pointer",
    padding: "6px 12px",
    borderRadius: 6,
    backgroundColor: active ? "#22C55E" : "#0F1620",
    color: active ? "#0B0F14" : "#E5E7DB",
    border: `1px solid #1F2A37`,
    userSelect: "none",
    fontWeight: active ? "bold" : "normal",
    minWidth: 32,
    textAlign: "center",
  }),
  exportButton: {
    cursor: "pointer",
    backgroundColor: "#0F1620",
    border: "1px solid #1F2A37",
    color: "#E5E7DB",
    padding: "8px 14px",
    borderRadius: 6,
    fontWeight: "bold",
    fontSize: 14,
    userSelect: "none",
    alignSelf: "flex-start",
    marginBottom: 12,
    transition: "background-color 0.25s",
  },
};

const TABS = [
  { key: "all", label: "All Trades" },
  { key: "dividends", label: "Dividends" },
  { key: "transfers", label: "Transfers" },
  { key: "fees", label: "Fees" },
];

const COLUMNS = [
  { key: "date", label: "Date" },
  { key: "type", label: "Type" },
  { key: "symbol", label: "Symbol" },
  { key: "qty", label: "Qty" },
  { key: "price", label: "Price" },
  { key: "total", label: "Total" },
  { key: "commission", label: "Commission" },
  { key: "pnl", label: "PnL" },
];

// No sample data — transactions loaded from API or shown as empty
const SAMPLE_DATA = [];

function formatDate(dateStr) {
  const d = new Date(dateStr);
  if (isNaN(d)) return "";
  return d.toISOString().slice(0, 10);
}

function formatNumber(num, decimals = 2) {
  return num.toLocaleString(undefined, {
    minimumFractionDigits: decimals,
    maximumFractionDigits: decimals,
  });
}

function exportCSV(data) {
  if (!data.length) return;
  const headers = COLUMNS.map((c) => c.label);
  const rows = data.map((row) =>
    COLUMNS.map((col) => {
      let val = row[col.key];
      if (col.key === "date") val = formatDate(val);
      else if (typeof val === "number") val = formatNumber(val);
      return `"${val}"`;
    })
  );
  const csvContent =
    [headers.join(","), ...rows.map((r) => r.join(","))].join("\r\n");
  const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = "transaction_ledger.csv";
  a.click();
  URL.revokeObjectURL(url);
}

export default function TransactionLedger() {
  const [activeTab, setActiveTab] = useState("all");
  const [search, setSearch] = useState("");
  const [dateFrom, setDateFrom] = useState("");
  const [dateTo, setDateTo] = useState("");
  const [sortConfig, setSortConfig] = useState({ key: "date", direction: "desc" });
  const [currentPage, setCurrentPage] = useState(1);

  // Filter by tab
  const filteredByTab = useMemo(() => {
    if (activeTab === "all") return SAMPLE_DATA;
    if (activeTab === "dividends") return SAMPLE_DATA.filter((t) => t.type.toLowerCase() === "dividend");
    if (activeTab === "transfers") return SAMPLE_DATA.filter((t) => t.type.toLowerCase() === "transfer");
    if (activeTab === "fees") return SAMPLE_DATA.filter((t) => t.type.toLowerCase() === "fee");
    return SAMPLE_DATA;
  }, [activeTab]);

  // Filter by date range
  const filteredByDate = useMemo(() => {
    return filteredByTab.filter((t) => {
      if (!dateFrom && !dateTo) return true;
      const d = new Date(t.date);
      if (dateFrom && d < new Date(dateFrom)) return false;
      if (dateTo && d > new Date(dateTo)) return false;
      return true;
    });
  }, [filteredByTab, dateFrom, dateTo]);

  // Filter by search (symbol, type)
  const filteredBySearch = useMemo(() => {
    if (!search.trim()) return filteredByDate;
    const lower = search.trim().toLowerCase();
    return filteredByDate.filter(
      (t) =>
        (t.symbol && t.symbol.toLowerCase().includes(lower)) ||
        (t.type && t.type.toLowerCase().includes(lower))
    );
  }, [filteredByDate, search]);

  // Sorting
  const sortedData = useMemo(() => {
    const sorted = [...filteredBySearch];
    const { key, direction } = sortConfig;
    sorted.sort((a, b) => {
      let aVal = a[key];
      let bVal = b[key];
      if (key === "date") {
        aVal = new Date(aVal);
        bVal = new Date(bVal);
      }
      if (typeof aVal === "string") aVal = aVal.toLowerCase();
      if (typeof bVal === "string") bVal = bVal.toLowerCase();

      if (aVal > bVal) return direction === "asc" ? 1 : -1;
      if (aVal < bVal) return direction === "asc" ? -1 : 1;
      return 0;
    });
    return sorted;
  }, [filteredBySearch, sortConfig]);

  // Pagination
  const ITEMS_PER_PAGE = 50;
  const totalPages = Math.max(1, Math.ceil(sortedData.length / ITEMS_PER_PAGE));
  const paginatedData = useMemo(() => {
    const start = (currentPage - 1) * ITEMS_PER_PAGE;
    return sortedData.slice(start, start + ITEMS_PER_PAGE);
  }, [sortedData, currentPage]);

  // Summary bar calculations (Realized PnL, Commissions, Dividends)
  const summary = useMemo(() => {
    let realizedPnl = 0;
    let commissions = 0;
    let dividends = 0;
    for (const t of filteredBySearch) {
      if (t.pnl) realizedPnl += t.pnl;
      if (t.commission) commissions += t.commission;
      if (t.type.toLowerCase() === "dividend" && t.total) dividends += t.total;
    }
    return { realizedPnl, commissions, dividends };
  }, [filteredBySearch]);

  // Handle sort click
  function onSortClick(colKey) {
    setCurrentPage(1);
    setSortConfig((old) => {
      if (old.key === colKey) {
        return {
          key: colKey,
          direction: old.direction === "asc" ? "desc" : "asc",
        };
      }
      return { key: colKey, direction: "asc" };
    });
  }

  // Render sort indicator
  function SortIndicator({ columnKey }) {
    if (sortConfig.key !== columnKey) return null;
    return (
      <span style={styles.thSortIndicator}>
        {sortConfig.direction === "asc" ? "▲" : "▼"}
      </span>
    );
  }

  // Pagination buttons (show max 7 pages with ellipsis)
  function PaginationButtons() {
    if (totalPages <= 1) return null;
    const buttons = [];
    let startPage = Math.max(1, currentPage - 3);
    let endPage = Math.min(totalPages, currentPage + 3);

    if (startPage > 1) {
      buttons.push(
        <div
          key={1}
          style={styles.pageButton(currentPage === 1)}
          onClick={() => setCurrentPage(1)}
          title="Page 1"
        >
          1
        </div>
      );
      if (startPage > 2) {
        buttons.push(
          <div key="start-ellipsis" style={{ padding: "6px 8px", userSelect: "none" }}>
            ...
          </div>
        );
      }
    }

    for (let i = startPage; i <= endPage; i++) {
      if (i === 1 || i === totalPages) continue;
      buttons.push(
        <div
          key={i}
          style={styles.pageButton(currentPage === i)}
          onClick={() => setCurrentPage(i)}
          title={`Page ${i}`}
        >
          {i}
        </div>
      );
    }

    if (endPage < totalPages) {
      if (endPage < totalPages - 1) {
        buttons.push(
          <div key="end-ellipsis" style={{ padding: "6px 8px", userSelect: "none" }}>
            ...
          </div>
        );
      }
      buttons.push(
        <div
          key={totalPages}
          style={styles.pageButton(currentPage === totalPages)}
          onClick={() => setCurrentPage(totalPages)}
          title={`Page ${totalPages}`}
        >
          {totalPages}
        </div>
      );
    }

    return (
      <div style={styles.pagination}>
        <div
          style={styles.pageButton(false)}
          onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
          title="Previous Page"
        >
          ‹
        </div>
        {buttons}
        <div
          style={styles.pageButton(false)}
          onClick={() => setCurrentPage((p) => Math.min(totalPages, p + 1))}
          title="Next Page"
        >
          ›
        </div>
      </div>
    );
  }

  return (
    <div style={styles.container} aria-label="Transaction Ledger">
      <h1 style={styles.header}>Transaction Ledger</h1>

      <nav aria-label="Filter tabs" style={styles.tabsContainer}>
        {TABS.map((tab) => (
          <div
            key={tab.key}
            role="tab"
            aria-selected={activeTab === tab.key}
            tabIndex={0}
            onClick={() => {
              setActiveTab(tab.key);
              setCurrentPage(1);
            }}
            onKeyDown={(e) => {
              if (e.key === "Enter" || e.key === " ") {
                setActiveTab(tab.key);
                setCurrentPage(1);
              }
            }}
            style={styles.tab(activeTab === tab.key)}
          >
            {tab.label}
          </div>
        ))}
      </nav>

      <div style={styles.filtersRow}>
        <label htmlFor="date-from" style={{ userSelect: "none" }}>
          From:&nbsp;
          <input
            id="date-from"
            type="date"
            value={dateFrom}
            onChange={(e) => {
              setDateFrom(e.target.value);
              setCurrentPage(1);
            }}
            style={styles.dateInput}
            max={dateTo || undefined}
          />
        </label>

        <label htmlFor="date-to" style={{ userSelect: "none" }}>
          To:&nbsp;
          <input
            id="date-to"
            type="date"
            value={dateTo}
            onChange={(e) => {
              setDateTo(e.target.value);
              setCurrentPage(1);
            }}
            style={styles.dateInput}
            min={dateFrom || undefined}
          />
        </label>

        <input
          type="search"
          aria-label="Search transactions"
          placeholder="Search symbol or type..."
          value={search}
          onChange={(e) => {
            setSearch(e.target.value);
            setCurrentPage(1);
          }}
          style={styles.searchInput}
        />

        <button
          type="button"
          onClick={() => exportCSV(sortedData)}
          style={styles.exportButton}
          aria-label="Export transactions to CSV"
        >
          Export CSV
        </button>
      </div>

      <div style={styles.tableWrapper}>
        <table role="table" style={styles.table}>
          <thead>
            <tr>
              {COLUMNS.map((col) => (
                <th
                  key={col.key}
                  role="columnheader"
                  tabIndex={0}
                  onClick={() => onSortClick(col.key)}
                  onKeyDown={(e) => {
                    if (e.key === "Enter" || e.key === " ") {
                      onSortClick(col.key);
                    }
                  }}
                  style={styles.th}
                  aria-sort={
                    sortConfig.key === col.key
                      ? sortConfig.direction === "asc"
                        ? "ascending"
                        : "descending"
                      : "none"
                  }
                  scope="col"
                >
                  {col.label}
                  <SortIndicator columnKey={col.key} />
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {paginatedData.length === 0 ? (
              <tr>
                <td colSpan={COLUMNS.length} style={{ ...styles.td, textAlign: "center" }}>
                  No transactions found.
                </td>
              </tr>
            ) : (
              paginatedData.map((t) => (
                <tr key={t.id}>
                  <td style={styles.td}>{formatDate(t.date)}</td>
                  <td style={styles.td}>{t.type}</td>
                  <td style={styles.td}>{t.symbol || "-"}</td>
                  <td style={styles.td}>{t.qty || "-"}</td>
                  <td style={styles.td}>
                    {t.price ? formatNumber(t.price) : "-"}
                  </td>
                  <td style={styles.td}>
                    {t.total ? formatNumber(t.total) : "-"}
                  </td>
                  <td style={styles.td}>
                    {t.commission ? formatNumber(t.commission) : "-"}
                  </td>
                  <td
                    style={{
                      ...styles.td,
                      ...(t.pnl > 0
                        ? styles.greenText
                        : t.pnl < 0
                        ? styles.redText
                        : {}),
                    }}
                  >
                    {t.pnl ? formatNumber(t.pnl) : "-"}
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      <PaginationButtons />

      <section
        aria-label="Summary bar"
        style={styles.summaryBar}
        role="region"
        tabIndex={-1}
      >
        <div style={styles.summaryItem}>
          Realized PnL:{" "}
          <span
            style={
              summary.realizedPnl > 0
                ? styles.greenText
                : summary.realizedPnl < 0
                ? styles.redText
                : {}
            }
          >
            {formatNumber(summary.realizedPnl)}
          </span>
        </div>
        <div style={styles.summaryItem}>
          Commissions: {formatNumber(summary.commissions)}
        </div>
        <div style={styles.summaryItem}>
          Dividends:{" "}
          <span style={styles.greenText}>{formatNumber(summary.dividends)}</span>
        </div>
      </section>
    </div>
  );
}
